// BusTrendChart.js
import React, { useEffect, useState } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";

function BusTrendChart({ data }) {
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    if (!data || data.length === 0) return;

    const now = new Date();
    const timestamp = `${now.getHours()}:${now.getMinutes()}:${now.getSeconds()}`;

    // Count buses by status
    const counts = data.reduce(
      (acc, bus) => {
        acc[bus.status] = (acc[bus.status] || 0) + 1;
        return acc;
      },
      { normal: 0, ghost: 0, anomaly: 0 }
    );

    // Add the current timestamp counts to chart data
    setChartData((prev) => [
      ...prev.slice(-20), // keep only last 20 data points
      { time: timestamp, ...counts },
    ]);
  }, [data]);

  return (
    <ResponsiveContainer width="100%" height={400}>
      <LineChart data={chartData}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="time" />
        <YAxis />
        <Tooltip />
        <Legend />
        <Line type="monotone" dataKey="normal" stroke="green" />
        <Line type="monotone" dataKey="ghost" stroke="red" />
        <Line type="monotone" dataKey="anomaly" stroke="orange" />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default BusTrendChart;
